export function isInit(msg: ScheduleUpdate): msg is Init {
  return msg.type == ScheduleUpdateType.INIT;
}

export function isActiveScheduleChange(msg: ScheduleUpdate): msg is ActiveScheduleChange {
  return msg.type == ScheduleUpdateType.ACTIVE_SCHEDULE_CHANGE;
}

