import { t } from 'ftc-common/i18n';
import {ParsedMatchTiming, renderTime} from "ftc-common/utils";
import { ControlMatch } from "./connection";
import { Alliance } from "../ref/Ref";
import {TimerData} from "ftc-common/hooks";
import {ActiveTimeout} from "ftc-common/displays/displayContainer";
import {isHaltedT206Timeout, isT206DependencyTimeout, isT206Timeout} from "ftc-common/timeoutUtils";
import {T206Timeout, TimeoutReference} from "ftc-common/javaTypes";
import {EventSettings} from "../javaTypes";

function displayAlliance(alliance: Alliance<any>) {
    let ret = `${alliance.team1Display}, ${alliance.team2Display}`
    if (alliance.team3) {
        ret += `, ${alliance.team3Display}`
    }
    return ret
}

const bothStillInTeleop = { style: { backgroundColor: '#F57E25' }, title: t`Still in TELEOP!` };
const scoringStillInTeleop = { style: { background: 'linear-gradient(#F57E25 0%, #F57E25 50%, #00000000 50%, #00000000 100%)' }, title: t`Scoring still in TELEOP!` };
const penaltyStillInTeleop = { style: { background: 'linear-gradient(#00000000 0%, #00000000 50%, #F57E25 50%, #F57E25 100%)' }, title: t`Penalty still in TELEOP!` };

const scoringStillInTeleopPenaltyReviewSubmitted = { style: { background: 'linear-gradient(#F57E25 0%, #F57E25 50%, #00C800 50%, #00C800 100%)' }, title: t`Scoring still in TELEOP, penalty submitted!` };
const penaltyStillInTeleopScoringReviewSubmitted = { style: { background: 'linear-gradient(#00C800 0%, #00C800 50%, #F57E25 50%, #F57E25 100%)' }, title: t`Penalty still in TELEOP, scoring submitted!` };

const bothReviewSubmitted = { style: { backgroundColor: '#00C800' }, title: t`Submitted!` };
const scoringReviewSubmitted = { style: { background: 'linear-gradient(#00C800 0%, #00C800 50%, #00000000 50%, #00000000 100%)' }, title: t`Scoring submitted!` };
const penaltyReviewSubmitted = { style: { background: 'linear-gradient(#00000000 0%, #00000000 50%, #00C800 50%, #00C800 100%)' }, title: t`Penalty submitted!` };

function computeDisplayStatus(alliance: Alliance<any>, penaltyTabletsEnabled?: boolean) {
    if(!alliance.scoringStatus.teleopSubmitted && !alliance.penaltyStatus.teleopSubmitted) {
        return bothStillInTeleop;
    } else if(!alliance.scoringStatus.teleopSubmitted && penaltyTabletsEnabled) {
        if(alliance.penaltyStatus.reviewSubmitted) {
            return scoringStillInTeleopPenaltyReviewSubmitted;
        } else {
            return scoringStillInTeleop;
        }
    } else if(!alliance.penaltyStatus.teleopSubmitted && penaltyTabletsEnabled) {
        if(alliance.scoringStatus.reviewSubmitted) {
            return penaltyStillInTeleopScoringReviewSubmitted;
        } else {
            return penaltyStillInTeleop;
        }
    } else if(alliance.scoringStatus.reviewSubmitted && (alliance.penaltyStatus.reviewSubmitted || !penaltyTabletsEnabled)) {
        return bothReviewSubmitted;
    } else if(alliance.scoringStatus.reviewSubmitted) {
        return scoringReviewSubmitted;
    } else if(alliance.penaltyStatus.reviewSubmitted) {
        return penaltyReviewSubmitted;
    }
    return {}
}

export default function CurrentMatches({loadedMatch, activeMatch, matchRemaining, timeoutTimer, timeout, compact, settings, timing}: {
    loadedMatch?: ControlMatch<any, any>,
    activeMatch?: ControlMatch<any, any>,
    matchRemaining: number,
    timeoutTimer?: TimerData,
    timeout?: TimeoutReference,
    compact?: boolean,
    settings: Partial<EventSettings>,
    timing: ParsedMatchTiming
}) {
    let remainingText = t`Complete`;
    let displayTimeRemaining = matchRemaining;
    if(matchRemaining > timing.teleop.add(timing.transition).total('seconds')) {
        remainingText = t`AUTO`;
        displayTimeRemaining = matchRemaining - timing.teleop.add(timing.transition).total('seconds');
    } else if(matchRemaining > timing.teleop.total('seconds')) {
        remainingText = t`Transition`;
        displayTimeRemaining = matchRemaining - timing.teleop.total('seconds');
    } else if(matchRemaining > 0) {
        remainingText = t`TELEOP`;
    }

    let redActiveStatus = {};
    let blueActiveStatus = {};
    // We only show status for active matches if the match is complete but unsubmitted
    if(activeMatch && (activeMatch.state === 'REVIEW' || activeMatch.state === 'SUBMITTED')) {
        redActiveStatus = computeDisplayStatus(activeMatch.red, settings.penaltyTabletsEnabled)
        blueActiveStatus = computeDisplayStatus(activeMatch.blue, settings.penaltyTabletsEnabled)
    }

    const notInitColor = settings.waitForInitSubmit ? 'red' : 'transparent';

    return <table className="mx-auto" style={compact ? {width: '100%'} : {minWidth: '800px'}}>
        <tbody>
        <tr>
            <th>{t`Loaded Match:`}</th>
            { loadedMatch ? <>
                <td>{compact ? loadedMatch.shortName : loadedMatch.name}</td>
                <td>{renderTime(timing.total.subtract(timing.transition).total('seconds'))} <span className={"d-none d-sm-inline"}>({loadedMatch.start > 0 ? t`Aborted` : t`Not Started`})</span></td>
                {compact ? <td>
                    <span style={{backgroundColor: loadedMatch.red.scoringStatus.initSubmitted ? '#00C800' : notInitColor}}>Red: {displayAlliance(loadedMatch.red)}</span><br/>
                    <span style={{backgroundColor: loadedMatch.blue.scoringStatus.initSubmitted ? '#00C800' : notInitColor}}>Blue: {displayAlliance(loadedMatch.blue)}</span>
                </td> : <>
                    <td style={{backgroundColor: loadedMatch.red.scoringStatus.initSubmitted ? '#00C800' : notInitColor}}>Red: {displayAlliance(loadedMatch.red)}</td>
                    <td style={{backgroundColor: loadedMatch.blue.scoringStatus.initSubmitted ? '#00C800' : notInitColor}}>Blue: {displayAlliance(loadedMatch.blue)}</td>
                </>}
            </> : null}
        </tr>
        <tr>
            <th>{t`Active Match:`}</th>
            {activeMatch ? <>
                <td>{compact ? activeMatch.shortName : activeMatch.name}</td>
                <td style={activeMatch.hrReview && activeMatch.state === 'REVIEW' ? {backgroundColor: 'yellow', color: 'black'} : {}}>{activeMatch.hrReview && activeMatch.state === 'REVIEW' ? t`Held for review` : <>{renderTime(displayTimeRemaining)} ({remainingText})</>}</td>
                {compact ? <td>
                    <span {...redActiveStatus}>Red: {displayAlliance(activeMatch.red)}</span><br/>
                    <span {...blueActiveStatus}>Blue: {displayAlliance(activeMatch.blue)}</span>
                </td> : <>
                    <td {...redActiveStatus}>Red: {displayAlliance(activeMatch.red)}</td>
                    <td {...blueActiveStatus}>Blue: {displayAlliance(activeMatch.blue)}</td>
                </>}
            </> : ((timeoutTimer && timeoutTimer.running) || (timeout && (isHaltedT206Timeout(timeout) || isT206DependencyTimeout(timeout))) ? <>
                <td></td>
                <td>{getTimeoutRender(timeoutTimer, timeout)} (Expected Start)</td>
            </> :null)}
        </tr>
        </tbody>
    </table>
}

function getTimeoutRender(timeoutTimer?: TimerData, timeout?: TimeoutReference) {
    if (timeout && isT206Timeout(timeout) && (timeout as T206Timeout).awaitingScorePost) {
        return "5:00+";
    }
    if (timeout && isT206DependencyTimeout(timeout)) {
        return "8:00+";
    }
    return timeoutTimer ? renderTime(timeoutTimer.remaining) : "";
}