import {Button, Col, Form, Modal, Row} from "react-bootstrap";
import {Dispatch, SetStateAction, useEffect, useState} from "react";
import {createTestMatch, loadPracticeMatch} from "./api/match";
import {useUniqueId} from "ftc-common/utils";
import { t } from "ftc-common/i18n";
import Select from "react-select";
import {useQuery} from "@tanstack/react-query";
import {ControlMatch} from "./connection";
import {Scores} from "../javaTypes";

interface MatchTeams {
    red1: string,
    red2: string,
    blue1: string,
    blue2: string,
}
const initTeams: MatchTeams = { red1: '-1', red2: '-2', blue1: '-3', blue2: '-4' }

const practiceTeams = [{ value: '0', label: `No Team Present`}]

const testTeams = [...Array(20).keys()].map(k =>
    ({ value: `-${k + 1}`, label: `-${k + 1} - Test Team ${k + 1}`})
)

function TeamPickerDialogBody({ eventCode, teams, setTeams, isPractice }: {
    eventCode: string,
    teams: MatchTeams,
    setTeams: Dispatch<SetStateAction<MatchTeams>>,
    isPractice?: boolean
}) {
    const idPrefix = useUniqueId();
    const {data: teamList} = useQuery<{value: string, label: string}[]>({
        queryKey: ['loadMatchTeamList', eventCode],
        queryFn: async () => {
            const res = await fetch(`/event/${eventCode}/dashboard/teams/data/`)
            const data = await res.json();
            return data.teams.map((t: any) => ({ value: t.data.number.toString(), label: `${t.data.displayNumber} - ${t.data.name}`}))
        }
    })
    const optionList = [...(teamList || []), ...(isPractice ? practiceTeams : testTeams)]

    return <Row className={"w-100"}>
        {(['Red', 'Blue'] as const).map((color) => {
            const colorLower = color.toLowerCase() as 'red' | 'blue';
            return <Col key={color}>
                {([1, 2] as const).map(i => (
                    <Form.Group className="m-2 flex-nowrap" controlId={`${idPrefix}_${colorLower}${i}`} key={i}>
                        <Form.Label className="mr-2 text-nowrap">{color} {i}</Form.Label>
                        <Select
                            className={`flex-grow-1 ${teams[`${colorLower}${i}`] != '0' && Object.values(teams).filter(t => t == teams[`${colorLower}${i}`]).length > 1 ? 'is-invalid' : ''}`}
                            value={optionList.find(x => x.value == teams[`${colorLower}${i}`])}
                            onChange={(v) => setTeams(t => ({...t, [`${colorLower}${i}`]: v!.value}))}
                            options={optionList}/>
                        <Form.Control.Feedback type="invalid" className={"ml-1 w-auto"}>
                            <i className={"fa fa-exclamation-triangle"}/> {t`Duplicate team`}
                        </Form.Control.Feedback>
                    </Form.Group>
                ))}
            </Col>
        })}
    </Row>
}

export function PracticeMatchDialog({close, eventCode, match}: {
    close: (success: boolean) => void, eventCode: string, match: ControlMatch<Scores, any>
}) {
    const [teams, setTeams] = useState({
        red1: '0',
        red2: '0',
        blue1: '0',
        blue2: '0',
    })
    const [error, setError] = useState("");

    useEffect(() => {
        setTeams({
            red1: match.red.team1.toString(),
            red2: match.red.team2.toString(),
            blue1: match.blue.team1.toString(),
            blue2: match.blue.team2.toString(),
        })
    }, [match.number]);

    function handleClose() {
        setError("")
        close(false)
    }

    async function loadMatch() {
        const res = await loadPracticeMatch(eventCode, match.number, teams);
        if(!res.success) {
            setError(res.message)
            return;
        } else {
            setError("")
            close(true)
        }
    }

    const realTeams = Object.values(teams).filter(t => t != '0');
    const hasDuplicates = new Set(realTeams).size < realTeams.length;

    return <Modal show onHide={handleClose} size="xl">
        <Modal.Header closeButton>
            <Modal.Title>{t`Load Practice Match ${match.number}`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            <Form inline>
                <TeamPickerDialogBody eventCode={eventCode} teams={teams} setTeams={setTeams} isPractice />
            </Form>
            <p className={"text-danger"}>{error}</p>
        </Modal.Body>
        <Modal.Footer>
            <Button variant="secondary" onClick={handleClose}>
                {t`Cancel`}
            </Button>
            <Button variant="primary" onClick={loadMatch} disabled={hasDuplicates}>
                {t`Load`}
            </Button>
        </Modal.Footer>
    </Modal>
}

export function TestMatchDialog({visible, close, eventCode, fieldCount}: {
    visible: boolean, close: () => void, eventCode: string, fieldCount: number
}) {
    const idPrefix = useUniqueId();
    const [teams, setTeams] = useState(initTeams)
    const [field, setField] = useState(0)
    const [training, setTraining] = useState(false);
    const [error, setError] = useState("");

    function handleClose() {
        setTeams(initTeams)
        setTraining(false)
        setError("")
        close()
    }
    
    async function createMatch() {
        const res = await createTestMatch(eventCode, teams, field, training);
        if(!res.success) {
            setError(res.message)
            return;
        }
        handleClose()
    }


    return <Modal show={visible} onHide={handleClose} size="xl">
        <Modal.Header closeButton>
            <Modal.Title>{t`Add Test Match`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            <Form inline>
                <TeamPickerDialogBody eventCode={eventCode} teams={teams} setTeams={setTeams} />
                <Row>
                    <Col>
                        <Form.Group className="m-2" controlId={`${idPrefix}_field`}>
                            <Form.Label className="mr-2">Field</Form.Label>
                            <Form.Control as="select" value={field} onChange={(e) => setField(parseInt((e.target as HTMLInputElement).value))} custom>
                                <option value="0">{t`Auto (alternating)`}</option>
                                {[ ...Array(fieldCount).keys() ].map( i => i+1).map(i => <option key={i} value={i.toString()}>{t`Field ${i}`}</option>)}
                            </Form.Control>
                        </Form.Group>
                    </Col>
                </Row>
                <Row>
                    <Col>
                        <Form.Group className="m-2" controlId={`${idPrefix}_training`}>
                            <Form.Label className="mr-2">Training <i className={"fa fa-question-circle ml-1"} title={t`If checked, the referees will get training information on their tablets.`}/> </Form.Label>
                            <Form.Check checked={training} onChange={(e) => setTraining(e.target.checked)}/>
                        </Form.Group>
                    </Col>
                </Row>
            </Form>
            <p>{t`Negative numbers (default) indicate a Test Team. You may replace the default number with the number of
               any team competing in this event. Setting the Field to 'Auto' will use the test match number to calculate
               appropriate field. Test matches are not saved, and all data associated with them will be lost when the
               system is shut down.`}</p>
            <p className={"text-danger"}>{error}</p>
        </Modal.Body>
        <Modal.Footer>
            <Button variant="secondary" onClick={handleClose}>
                {t`Cancel`}
            </Button>
            <Button variant="primary" onClick={createMatch}>
                {t`Add`}
            </Button>
        </Modal.Footer>
    </Modal>
}