export async function abortMatch(eventCode: string, number: number, isDiscard?: boolean) {
  if(!await confirmDialog({
    label: isDiscard ? t`Discard Match Results?` : t`Abort Match?`,
    text: t`This will reset the current match and discard all scores.`,
    buttonText: isDiscard ? t`Discard` : t`Abort`
  })) {
    return;
  }
  if(!await matchApi.abortMatch(eventCode, number)) {
    messageDialog({
      label: t`Failed to Abort Match`,
      text: t`Match abort failed.  Please refresh and try again.`
    })
  }
}

export async function commitMatch(eventCode: string, number: number, existingMatches: ControlMatch<any, any>[], withPost = false, verifyCommit = true) {
  const {ok, status, result} = await matchApi.commitMatch(eventCode, number, withPost);
  if(!ok) {
    await messageDialog({
      label: t`Failed to Commit Match`,
      text: status && [422, 432].includes(status) ? result :
        t`Failed to commit scores! Data may not be saved.
                Make sure your connection to the server is OK, and try again.
                If you continue to see this message, contact your FTA or FIRST Support.
                If using live scoring, do not restart the server without saving a screenshot of the scores for this match.`
    })
    return false
  } else {
    const existingMatch = existingMatches.find(m => m.number === number);
    if(verifyCommit && existingMatch && !isEqual({ red: result.red, blue: result.blue }, { red: existingMatch.red.scores, blue: existingMatch.blue.scores })) {
      console.warn("Committed scores do not match existing scores", { red: result.red, blue: result.blue }, { red: existingMatch.red.scores, blue: existingMatch.blue.scores });
      Sentry.captureMessage("Commit data mismatch\n" + JSON.stringify([{ red: result.red, blue: result.blue }, { red: existingMatch.red.scores, blue: existingMatch.blue.scores }]));
      await messageDialog({
        label: t`Commit Data Mismatch`,
        text: t`Warning! The scores saved to the database may not match the scores shown here.
            Edit the match and verify the scores are correct and try again.
            If you continue to see the message contact FIRST support.`
      });
      return false
    }
    return true
  }
}


