import {Button, ButtonGroup, Dropdown} from "react-bootstrap";
import { t } from 'ftc-common/i18n';

import "./ActionButtons.css";
import {ControlMatch} from "./connection";
import { DisplayCommand } from "ftc-common/javaTypes";
import { EventSettings } from "../javaTypes";
import { ButtonVariant } from "react-bootstrap/types";
import {useCallback} from "react";

type buttonStatus = { disabled: boolean, variant: ButtonVariant } | null;
const DISABLED_STATUS: buttonStatus = { disabled: true, variant: 'light' };
const GOOD_STATUS: buttonStatus = { disabled: false, variant: 'success' };
const WARNING_STATUS: buttonStatus = { disabled: false, variant: 'warning' };
const DANGER_STATUS: buttonStatus = { disabled: false, variant: 'danger' };

function commandForMatch(command: DisplayCommand<any>, match: ControlMatch<any, any>) {
    return command.params.matchName === match.name || command.params.matchName.startsWith(match.name + " of ")
}

export default function ActionButtons({hasNextMatch, loadNextMatch, loadedMatch, activeMatch, matches, editingMatch, previewMatch, randomizeMatch, showRandom,
                            showMatch, startMatch, abortMatch, commitAndPostMatch, commitMatch, batchPost, displayUpdates, settings, isArchived, warnIfNotPost, showSeparatePreviews, controlSettings}:
                          {hasNextMatch: boolean, loadNextMatch: () => void, loadedMatch?: ControlMatch<any, any>, activeMatch?: ControlMatch<any, any>, matches?: ControlMatch<any, any>[], editingMatch?: ControlMatch<any, any>,
                            previewMatch: (number: number, forceFullscreen?: boolean) => void, showMatch: (number: number) => void, startMatch: (number: number) => void,
                            randomizeMatch: (number: number, opts: {  confirm: boolean, random?: number }) => void, showRandom: (number: number) => void,
                            abortMatch: (number: number, isDiscard?: boolean) => void, commitAndPostMatch: (number: number) => void,
                            commitMatch: (number: number) => Promise<boolean>, batchPost: (number: number) => void,
                            displayUpdates: DisplayCommand<any>[], settings: Partial<EventSettings>, isArchived: boolean, warnIfNotPost: boolean, controlSettings: string, showSeparatePreviews?: boolean}) {
    const activeMatchRunning = activeMatch && activeMatch?.state !== 'REVIEW' && activeMatch?.state !== 'SUBMITTED'

    let loadStatus = DISABLED_STATUS;
    if(hasNextMatch && !isArchived) {
        loadStatus = GOOD_STATUS;
    }

    let previewStatus = DISABLED_STATUS;
    // Can only preview if a match is on-deck and no match is running
    if(loadedMatch && !activeMatchRunning) {
        // Warn if match is not yet randomized and not already previewed
        if(loadedMatch.state === 'UNPLAYED' && !displayUpdates.find(u => commandForMatch(u, loadedMatch) && u.type === 'SHOW_PREVIEW')) {
            previewStatus = GOOD_STATUS;
        } else {
            previewStatus = WARNING_STATUS;
        }
    }

    let randomizeStatus = DISABLED_STATUS;
    // Can always randomize if a match is on-deck
    if(loadedMatch) {
        // Scary warning if match is already yet randomized!!
        if(loadedMatch.state === 'UNPLAYED') {
            randomizeStatus = GOOD_STATUS;
        } else {
            randomizeStatus = DANGER_STATUS;
        }
    }

    let showRandomStatus = DISABLED_STATUS;
    // Can only show randomization if a match is on-deck, randomized, and no match is running
    if(loadedMatch && loadedMatch.state === 'RANDOMIZED' && !activeMatchRunning) {
        // Warn if randomization is already shown
        if(!displayUpdates.find(u => commandForMatch(u, loadedMatch) && u.type === 'SHOW_RANDOM')) {
            showRandomStatus = GOOD_STATUS;
        } else {
            showRandomStatus = WARNING_STATUS;
        }
    }

    let showMatchStatus: buttonStatus = { disabled: true, variant: 'light'}
    // Can only show in-match screen if a match is on-deck, randomized, and no match is running
    // randomization is only required for live scoring, since it could be entered after the fact for paper
    if(loadedMatch && (loadedMatch.state === 'RANDOMIZED' || !settings.liveScoring) && !activeMatchRunning) {
        // Warn if match is already shown
        if(!displayUpdates.find(u => commandForMatch(u, loadedMatch) && u.type === 'SHOW_MATCH')) {
            showMatchStatus = GOOD_STATUS;
        } else {
            showMatchStatus = WARNING_STATUS;
        }
    }

    let startMatchStatus: buttonStatus = DISABLED_STATUS;
    let abortMatchStatus = null;
    let canDiscardMatch = activeMatch && (activeMatch.state == 'REVIEW' || activeMatch.state == 'SUBMITTED') && !loadedMatch
    // If a match is in flight, for obvious reasons another match can't start but we need to be able to abort one
    if(activeMatchRunning || canDiscardMatch) {
        startMatchStatus = null;
        abortMatchStatus = DANGER_STATUS;
    // Can only start a match if a match is on-deck, randomized, and no other match is running
    } else if(loadedMatch && loadedMatch.state === 'RANDOMIZED' && !activeMatchRunning) {
         // Show a warning if either ref isn't ready and we are using live scoring
         if((loadedMatch.red.scoringStatus.initSubmitted && loadedMatch.blue.scoringStatus.initSubmitted) || !settings.liveScoring) {
             if (warnIfNotPost && activeMatch && activeMatch.postedTime < activeMatch.start) {
                 startMatchStatus = DANGER_STATUS;
             } else {
                 startMatchStatus = GOOD_STATUS;
             }
         } else {
             if (settings.waitForInitSubmit) {
                 startMatchStatus = DISABLED_STATUS;
             } else {
                 startMatchStatus = DANGER_STATUS;
             }
         }
    }

    let commitAndPostStatus = DISABLED_STATUS;
    // Check loaded match if no active so the button shows the right thing mid-round-robin when there is no active match
    const isRoundRobin = activeMatch ? activeMatch.seriesDescription?.matchesToWin == 0 : loadedMatch?.seriesDescription?.matchesToWin == 0
    if(isRoundRobin) {
        if(matches && activeMatch) {
            const wholeRound = matches.filter(m2 => m2.seriesDescription?.round === activeMatch.seriesDescription?.round);
            // Allow committed for round robin in case a single match gets manually edited and accidentally committed
            if(wholeRound.every(m => m.state === 'SUBMITTED' || m.state === 'COMMITTED') && wholeRound.some(m => m.state === 'SUBMITTED')
                && !wholeRound.some(m => m.number == editingMatch?.number)) {
                commitAndPostStatus = GOOD_STATUS;
            }
        }
    } else {
        // Can only commit and post if there is an active match that referees are done with and live scoring is in use and that match is not being edited
        if (activeMatch && activeMatch.state === 'SUBMITTED' && settings.liveScoring && activeMatch.number !== editingMatch?.number) {
            commitAndPostStatus = GOOD_STATUS;
        }
    }


    const fieldNumber = 'field_' + loadedMatch?.field || '';

    const commitAndPostRound = useCallback(async (round: number | undefined) => {
        if(!round || !matches) return;

        const wholeRound = matches.filter(m2 => m2.seriesDescription?.round === round);
        for (const match of wholeRound.filter(m => m.state === 'SUBMITTED')) {
            if(!await commitMatch(match.number)) {
                return
            }
        }
        batchPost(round);
    }, [matches]);

    return <div className="controlActionButtons d-flex justify-content-center">
        {/*load match*/}
        {['FULL'].includes(controlSettings) ?
            <Button {...loadStatus}
                onClick={loadNextMatch}
                className={"ml-auto mr-2 loadNextMatch"}>{t`Load Next\nMatch`}</Button>
            : null}
        {/*preview match*/}
        {['FULL'].includes(controlSettings) ?
            <>{showSeparatePreviews ? <>
                    <Button {...previewStatus}
                            onClick={() => previewMatch(loadedMatch!.number, true)}
                            className={"mx-2"}>{t`Fullscreen\nPreview`}</Button>
                    <Button {...previewStatus}
                            onClick={() => previewMatch(loadedMatch!.number)}
                            className={"mx-2 previewMatch"}>{t`Overlay\nPreview`}</Button>
                </> : <Button {...previewStatus}
                          onClick={() => previewMatch(loadedMatch!.number)}
                          className={"mx-2 previewMatch"}>{t`Show\nPreview`}</Button>}</>
            : null}
        {/*randomization*/}
        {['RANDOM', 'START_RANDOM', 'FULL'].includes(controlSettings) ?
            <>{settings.externalRandom ? <Dropdown as={ButtonGroup} className={"mx-2"}>
                    <Button {...randomizeStatus} onClick={() => randomizeMatch(loadedMatch!.number, { confirm: loadedMatch!.state !== 'UNPLAYED' })}>{t`Randomize\nField`}</Button>
                    <Dropdown.Toggle split {...randomizeStatus} />
                    <Dropdown.Menu>
                        <Dropdown.Item onClick={() => randomizeMatch(loadedMatch!.number, { random: 1, confirm: loadedMatch!.state !== 'UNPLAYED' })}>1 (GPP)</Dropdown.Item>
                        <Dropdown.Item onClick={() => randomizeMatch(loadedMatch!.number, { random: 2, confirm: loadedMatch!.state !== 'UNPLAYED' })}>2 (PGP)</Dropdown.Item>
                        <Dropdown.Item onClick={() => randomizeMatch(loadedMatch!.number, { random: 3, confirm: loadedMatch!.state !== 'UNPLAYED' })}>3 (PPG)</Dropdown.Item>
                    </Dropdown.Menu>
                </Dropdown> :
                <Button {...randomizeStatus}
                                  onClick={() => randomizeMatch(loadedMatch!.number, { confirm: loadedMatch!.state !== 'UNPLAYED' })}
                                  className={"mx-2 randomizeField"}>{t`Randomize\nField`}</Button>}</>
            : null}
        {/*show random*/}
        {['FULL'].includes(controlSettings) ?
            <Button {...showRandomStatus}
                    onClick={() => showRandom(loadedMatch!.number)}
                    className={"mx-2"}>{t`Show\nRandom`}</Button>
            : null}
        {/*show random*/}
        {['FULL'].includes(controlSettings) ?
            <Button {...showMatchStatus}
                    onClick={() => showMatch(loadedMatch!.number)}
                    className={"mx-2 showMatch"}>{t`Show\nMatch`}</Button>
            : null}
        {/*start/abort*/}
        {['START', 'START_RANDOM', 'FULL'].includes(controlSettings) ?
            <>{startMatchStatus ? <Button {...startMatchStatus}
                    onClick={() => startMatch(loadedMatch!.number)}
                    className={`mx-2 startMatch ${fieldNumber}`}>{t`Start\nMatch`}</Button> : null}
            {abortMatchStatus ? <Button {...abortMatchStatus}
                    onClick={() => abortMatch(activeMatch!.number, canDiscardMatch)}
                    className={"mx-2 abortMatch"}>{canDiscardMatch ? t`Discard\nMatch` : t`Abort\nMatch`}</Button> : null}</>
            : null}
        {/*commit and post*/}
        {['FULL'].includes(controlSettings) ?
            <Button {...commitAndPostStatus} onClick={() => isRoundRobin ? commitAndPostRound(activeMatch!.seriesDescription?.round) : commitAndPostMatch(activeMatch!.number)} className={"ml-auto mr-3 commitAndPostMatch"}>{isRoundRobin ? t`Commit & Post\nLast Round` : t`Commit & Post\nLast Match`}</Button>
            : null }
    </div>
}