import { PermissiveURLSearchParams } from "ftc-common/utils";

export async function loadMatch(eventCode: string, number: number) {
    const res = await fetch(`/event/${eventCode}/control/load/${number}/`, {
        method: "POST"
    })
    return res.ok;
}

export async function loadPracticeMatch(eventCode: string, number: number, teams: {red1: string, red2: string, blue1: string, blue2: string}) {
    const res = await fetch(`/event/${eventCode}/control/load/${number}/`, {
        method: 'POST',
        body: PermissiveURLSearchParams(teams)
    })
    return {
        success: res.ok,
        message: await res.text()
    };
}

export async function previewMatch(eventCode: string, number: number, forceFullscreen?: boolean) {
    const res = await fetch(`/event/${eventCode}/control/preview/${number}/`, {
        method: "POST",
        body: PermissiveURLSearchParams({forceFullscreen: forceFullscreen || false})
    })
    return res.ok;
}

export async function randomizeMatch(eventCode: string, number: number, random?: number) {
    const res = await fetch(`/event/${eventCode}/control/randomize/${number}/`, {
        method: "POST",
        body: random === undefined ? '' : PermissiveURLSearchParams({val: random})
    })
    return res.ok ? (await res.json())["random"] : null;
}

