export async function getMatchScore(eventCode: string, number: number) {
    const res = await fetch(`/event/${eventCode}/control/getmatchscore/${number}/`)
    if(!res.ok) {
        return null
    }
    const ret = await res.json();
    ret.red = JSON.parse(ret.red);
    ret.blue = JSON.parse(ret.blue);
    ret.redBreakdown = JSON.parse(ret.redBreakdown);
    ret.blueBreakdown = JSON.parse(ret.blueBreakdown);
    return ret;
}

