export async function commitMatch(eventCode: string, number: number, withPost: boolean) {
    try {
        const res = await fetch(`/event/${eventCode}/control/${withPost ? 'commitandpost' : 'commit'}/${number}/`, {
            method: 'POST',
        })
        if(!res.ok) {
            return { ok: false, status: res.status, result: await res.text()}
        } else {
            const ret = await res.json();
            ret.red = JSON.parse(ret.red);
            ret.blue = JSON.parse(ret.blue);
            return { ok: true, result: ret };
        }
    } catch(ex) {
        console.error("Commit failed", ex);
        return { ok: false }
    }
}

